#include <stdio.h>
#include <omp.h>

int main() {
    int N = 1000000;
    double A[N];
    double sum = 0.0;

    // Initialize array
    for (int i = 0; i < N; i++) {
        A[i] = 1.0;
    }

    // Parallel reduction
    #pragma omp parallel for reduction(+:sum)
    for (int i = 0; i < N; i++) {
        sum += A[i];
    }

    printf("Sum = %f\n", sum);
    return 0;
}

#include <stdio.h>
#include <omp.h>

#define BUFFER_SIZE 10
#define NUM_ITEMS 50

int buffer[BUFFER_SIZE];
int in = 0, out = 0;
int count = 0;

void producer(int id) {
    for (int i = 0; i < NUM_ITEMS; i++) {
        #pragma omp critical(producer)
        {
            while (count == BUFFER_SIZE); // Buffer full
            buffer[in] = i;
            in = (in + 1) % BUFFER_SIZE;
            count++;
            printf("Producer %d produced item %d\n", id, i);
        }
    }
}

void consumer(int id) {
    for (int i = 0; i < NUM_ITEMS; i++) {
        #pragma omp critical(consumer)
        {
            while (count == 0); // Buffer empty
            int item = buffer[out];
            out = (out + 1) % BUFFER_SIZE;
            count--;
            printf("Consumer %d consumed item %d\n", id, item);
        }
    }
}

int main() {
    #pragma omp parallel num_threads(4)
    {
        int tid = omp_get_thread_num();
        if (tid < 2) producer(tid);
        else consumer(tid);
    }
    return 0;
}

#include <stdio.h>
#include <omp.h>

void quicksort(int arr[], int low, int high) {
    if (low < high) {
        int pivot = arr[high];
        int i = low - 1;

        for (int j = low; j < high; j++) {
            if (arr[j] <= pivot) {
                i++;
                int temp = arr[i];
                arr[i] = arr[j];
                arr[j] = temp;
            }
        }
        int temp = arr[i + 1];
        arr[i + 1] = arr[high];
        arr[high] = temp;
        int pi = i + 1;

        // Create tasks for recursive calls
        #pragma omp task
        quicksort(arr, low, pi - 1);

        #pragma omp task
        quicksort(arr, pi + 1, high);

        // Wait for both subarrays to be sorted
        #pragma omp taskwait
    }
}

int main() {
    int arr[] = {10, 7, 8, 9, 1, 5};
    int n = sizeof(arr) / sizeof(arr[0]);

    #pragma omp parallel
    {
        #pragma omp single
        quicksort(arr, 0, n - 1);
    }

    printf("Sorted array: ");
    for (int i = 0; i < n; i++)
        printf("%d ", arr[i]);
    printf("\n");
    return 0;
}
